+#[cfg_attr(not(debug_assertions), unsafe(no_mangle))]
+pub unsafe extern "C" fn mktime(tm: *mut libc::tm) -> i64 {
+    if tm.is_null() {
+        unsafe { set_abi_errno(errno::EFAULT) };
+        return -1;
